scwin.retrieveChassisNo_tproCb = function (rtnList) {
  var row = scwin.rowChk;
  if (scwin.gridFlag == true) {
    if (!$c.gus.cfIsNull($p, rtnList) && rtnList[0] != "N/A") {
      var v_odrNo = ds_results.getCellData(row, "odrNo");
      var v_cntrSeq = ds_results.getCellData(row, "cntrSeq");
      for (var i = 0; i <= ds_results.getRowCount(); i++) {
        if (v_odrNo == ds_results.getCellData(i, "odrNo") && v_cntrSeq == ds_results.getCellData(i, "cntrSeq") && "0047" != ds_results.getCellData(i, "wrkStpCd")) {
          ds_results.setCellData(i, "chassShortNo", rtnList[0]);
        }
      }
    } else {
      ds_results.setCellData(row, "chassShortNo", "");
    }
  } else {
    if (rtnList == 'N/A') {
      ed_shortChassNo.setValue("");
    } else {
      $c.gus.cfSetReturnValue($p, rtnList, ed_shortChassNo, hid_chassisNo);
      hid_chassisEqCd.setValue(rtnList[4]);
      hid_chassisKndCd.setValue(rtnList[2]);
    }
  }
};

