//-------------------------------------------------------------------------
// function name : f_deleteRow
// function desc : 배차취소 버튼 누를때 실행
//-------------------------------------------------------------------------
scwin.f_deleteRow = function () {
  var row = ds_results.getRowPosition();
  ds_results.undoRow(row);
  if (acb_qryClsCd.getValue() == "Y") {
    /*
    var preChecked = chk_retrvStpYn.checked;
    if(chk_retrvStpYn.checked){
        chk_retrvStpYn.checked = false;
        f_filter();
    }
    */
    var unCheckedRow = ds_results.getRowPosition();
    for (var i = 0; i <= ds_results.getRowCount(); i++) {
      if (ds_results.getCellData(unCheckedRow, "transWrkIndictNo") == ds_results.getCellData(i, "transWrkIndictNo")) {
        if (acb_qryClsCd.getValue() == "Y") {
          //협력업체 배차 아닌경우
          if (ds_results.getCellData(i, "cooperatorYn") == 0) {
            ds_results.setCellData(i, "vehclNo", "");
            ds_results.setCellData(i, "vehclShortNo", "");
          } else {
            //협력업체배차인 경우
            ds_results.setCellData(i, "vehclClntNo", "");
            ds_results.setCellData(i, "vehclShortNo", "");
          }
          //ds_results.DeleteRow(i);
        }
      } //if
    } //for
    /*
    if(preChecked){
        chk_retrvStpYn.checked = true;
        f_filter();
    }
    */
  } //if
};
//-------------------------------------------------------------------------
// function name : f_setVehclClntNoToChecked()
// function desc : 협력업체 지정 버튼 클릭시
//-------------------------------------------------------------------------
scwin.f_setVehclNoAndChassisToChecked = function () {
  if (ed_shortVhclNo.getValue() == "" && ed_shortChassNo.getValue() == "") {
    alert("차량이나 샤시를 선택하여 주십시오");
    ed_shortVhclNo.focus();
    return false;
  }
  var chkCnt = 0;
  for (var i = 0; i <= ds_results.getRowCount(); i++) {
    if (ds_results.getCellData(i, "chk") == "1") {
      ds_results.setCellData(i, "vehclShortNo", ed_shortVhclNo.getValue());
      ds_results.setCellData(i, "vehclNo", hid_vehclNo.getValue());
      ds_results.setCellData(i, "vehclClntNo", hid_vehclClntNo.getValue());
      ds_results.setCellData(i, "vehclClntNm", hid_vehclClntNm.getValue());
      ds_results.setCellData(i, "drvNm", hid_drvNm.getValue());
      ds_results.setCellData(i, "mpNo", hid_mpNo.getValue());
      ds_results.setCellData(i, "eqCd", hid_eqCd.getValue());
      ds_results.setCellData(i, "pdaYn", hid_pdaYn.getValue());
      ds_results.setCellData(i, "chassShortNo", ed_shortChassNo.getValue());
      ds_results.setCellData(i, "chassisEqCd", hid_chassisEqCd.getValue());
      ds_results.setCellData(i, "chassisKndCd", hid_chassisKndCd.getValue());
      scwin.f_checkChasisNo(i);
      chkCnt++;
    }
  }
  if (chkCnt == 0) {
    $c.win.alert($p, "check된 물량이 없습니다. 원하는 물량을 체크한 후에 차량배정 버튼을 누르면 체크된 행에 차량과 샤시번호가 setting됩니다");
    return false;
  }
};

