//------------------------------------------------------------------------- 
scwin.f_vehclPopup = async function () {
  let opt = {};
  let data = {
    vehclShortNo: ed_shortVhclNo.getValue(),
    whereAreYouFrom: "T"
  };
  opt.width = "850";
  opt.height = "500";
  opt.id = "popUpAutoCreation";
  opt.title = "차량정보";
  opt.popupName = "차량정보";
  opt.type = "browserPopup";

  //실제호출
  rtnList = await $c.win.openPopup($p, "/ui/tn/op/transwrkindict/cntr/tn_304_01_05p.xml", opt, data);

  // var pURL = "/tn/op/transwrkindict/cntr/tn_304_01_05p.jsp?paramTitle=차량정보"
  //             + "&vehclShortNo="+em_shortVhclNo.Text
  //             + "&whereAreYouFrom=T"
  //             ;
  // rtnList = window.showModalDialog(pURL,"","dialogWidth:600px; dialogHeight:500px");

  if (!$c.gus.cfIsNull($p, rtnList) && rtnList[0] != "N/A") {
    ed_shortVhclNo.setValue(rtnList[0]);
    hid_vehclNo.setValue(rtnList[1]);
    hid_vehclClntNo.setValue(rtnList[7]);
    hid_vehclClntNm.setValue(rtnList[8]);
    hid_drvNm.setValue(rtnList[18]);
    hid_mpNo.setValue(rtnList[17]);
    hid_eqCd.setValue(rtnList[4]);
    hid_pdaYn.setValue(rtnList[19]);
  }
};
scwin.f_vehclPopup2 = async function (row, value) {
  let opt = {};
  let data = {
    vehclShortNo: value,
    whereAreYouFrom: "T"
  };
  opt.width = "850";
  opt.height = "500";
  opt.id = "popUpAutoCreation";
  opt.title = "차량정보";
  opt.popupName = "차량정보";
  opt.type = "browserPopup";

  //실제호출
  rtnList = await $c.win.openPopup($p, "/ui/tn/op/transwrkindict/cntr/tn_304_01_05p.xml", opt, data);
  if (!$c.gus.cfIsNull($p, rtnList) && rtnList[0] != "N/A") {
    var v_odrNo = ds_results.getCellData(row, "odrNo");
    var v_cntrSeq = ds_results.getCellData(row, "cntrSeq");
    for (var i = 0; i <= ds_results.getRowCount(); i++) {
      if (v_odrNo == ds_results.getCellData(i, "odrNo") && v_cntrSeq == ds_results.getCellData(i, "cntrSeq") && "0047" != ds_results.getCellData(i, "wrkStpCd")) {
        ds_results.setCellData(i, "vehclShortNo", rtnList[0]);
        ds_results.setCellData(i, "vehclNo", rtnList[1]);
      }
    }
  } else {
    ds_results.setCellData(row, "vehclShortNo", "");
    ds_results.setCellData(row, "vehclNo", "");
  }
};
scwin.openPop = function (rowIndex, colId, nowValue) {
  switch (colId) {
    case "vehclShortNo":
      scwin.f_retrieveVehclInGrid(rowIndex);
      break;
    case "chassShortNo":
      //scwin.f_openCommPopUpGrid( 2, rowIndex, 'T' );
      scwin.udc_chassi2_onclickEvent(rowIndex);
      break;
    case "dcScNm":
      scwin.f_dcScSearch();
      break;
  }
  ;
};
scwin.gr_results_oncellclick = function (rowIndex, columnIndex, columnId) {
  var colid = columnIndex;
  if (colid == "combine") {
    if (ds_results.getCellData(row, "combine") == "1") {
      if (ds_results.getCellData(row, "cmpstcrgNo") != "") {
        $c.win.alert($p, "컨테이너" + ds_results.getCellData(row, "cntrNo") + "는 이미 combine된 컨테이너입니다.");
        ds_results.undoRow(rowIndex);
        return false;
      }
    }
  }
  var v_odrNo = ds_results.getCellData(rowIndex, "odrNo");
  var v_cntrSeq = ds_results.getCellData(rowIndex, "cntrSeq");
  var v_chk = ds_results.getCellData(rowIndex, "chk");
  if ("0047" != ds_results.getCellData(rowIndex, "wrkStpCd")) {
    for (var i = 0; i <= ds_results.getRowCount(); i++) {
      if (i != rowIndex && v_odrNo == ds_results.getCellData(i, "odrNo") && v_cntrSeq == ds_results.getCellData(i, "cntrSeq") && "0047" != ds_results.getCellData(i, "wrkStpCd")) {
        ds_results.setCellData(i, "chk", v_chk);
      }
    } //for
  }
};
scwin.gr_results_oneditend = function (rowIndex, columnIndex, value) {
  switch (columnIndex) {
    case "11":
      if (ds_results.getCellData(rowIndex, "vehclShortNo") == "") {
        ds_results.setCellData(rowIndex, "vehclShortNo", "");
        ds_results.setCellData(rowIndex, "vehclNo", "");
        ds_results.setCellData(rowIndex, "vehclClntNo", "");
        ds_results.setCellData(rowIndex, "vehclClntNm", "");
        ds_results.setCellData(rowIndex, "drvNm", "");
        ds_results.setCellData(rowIndex, "mpNo", "");
        ds_results.setCellData(rowIndex, "eqCd", "");
        ds_results.setCellData(rowIndex, "chassShortNo", "");
        ds_results.setCellData(rowIndex, "chassisEqCd", "");
        ds_results.setCellData(rowIndex, "chassisKndCd", "");
        ds_results.setCellData(rowIndex, "chassisVehclNo", "");
      } else {
        //alert("pcy1");
        scwin.f_retrieveVehclInGrid();
      }
      break;
    case "14":
      scwin.f_openCommPopUpGrid(2, rowIndex, 'T');
      break;
    case "16":
      if (ds_results.getCellData(rowIndex, "cntrWrkShapeCd") != "") {
        if (ds_results.getCellData(rowIndex, "wrkStpCd") == "0002") {
          for (var i = 0; i <= ds_results.getRowCount(); i++) {
            if (ds_results.getCellData(rowIndex, "odrNo") == ds_results.getCellData(i, "odrNo") && ds_results.getCellData(rowIndex, "cntrSeq") == ds_results.getCellData(i, "cntrSeq") && ds_results.getCellData(i, "wrkStpCd") == "0003") {
              ds_results.setCellData(i, "vehclShortNo", "");
              ds_results.setCellData(i, "vehclNo", "");
              ds_results.setCellData(i, "vehclClntNo", "");
              ds_results.setCellData(i, "vehclClntNm", "");
              ds_results.setCellData(i, "drvNm", "");
              ds_results.setCellData(i, "mpNo", "");
              ds_results.setCellData(i, "eqCd", "");
              ds_results.setCellData(i, "chassShortNo", "");
              ds_results.setCellData(i, "chassisEqCd", "");
              ds_results.setCellData(i, "chassisKndCd", "");
              ds_results.setCellData(i, "chassisVehclNo", "");
              break;
            }
          }
        } else {
          alert("DOOR운송 단계만 선택할 수 있습니다.");
          ds_results.Undo(row);
          return false;
        }
      } else {
        ds_results.setCellData(rowIndex, "vehclShortNo", "");
        ds_results.setCellData(rowIndex, "vehclNo", "");
        ds_results.setCellData(rowIndex, "vehclClntNo", "");
        ds_results.setCellData(rowIndex, "vehclClntNm", "");
        ds_results.setCellData(rowIndex, "drvNm", "");
        ds_results.setCellData(rowIndex, "mpNo", "");
        ds_results.setCellData(rowIndex, "eqCd", "");
        ds_results.setCellData(rowIndex, "chassShortNo", "");
        ds_results.setCellData(rowIndex, "chassisEqCd", "");
        ds_results.setCellData(rowIndex, "chassisKndCd", "");
        ds_results.setCellData(rowIndex, "chassisVehclNo", "");
      }
      break;
  }
};
